section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/hidden-tech-debt-trace.json",
  "title": "hidden-tech-debt-trace",
  "type": "object",
  "required": [
    "artefact_id",
    "owner",
    "last_touched",
    "template_version",
    "status",
    "evidence",
    "report_id",
    "findings",
    "recommendations"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "minLength": 1,
      "description": "slug + ISO date or UUID"
    },
    "owner": {
      "type": "string",
      "minLength": 1,
      "description": "single named owner; generic group terms forbidden"
    },
    "last_touched": {
      "type": "string",
      "format": "date-time",
      "description": "ISO-8601 timestamp"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "report_id": {
      "type": "string",
      "minLength": 1
    },
    "findings": {
      "type": "array",
      "minItems": 1
    },
    "recommendations": {
      "type": "array",
      "minItems": 1
    }
  },
  "additionalProperties": false
}
